1277	        // Update ticket status with inventory management
1278	        function updateTicketStatus(id, status) {
1279	            const ticket = db.tickets.find(t => t.id === id);
1280	            if (!ticket) return;
1281	
1282	            const prevStatus = ticket.status;
1283	            ticket.status = status;
1284	
1285	            // Si se confirma o completa, reducir inventario
1286	            if ((status === 'confirmed' || status === 'completed') && prevStatus !== 'confirmed' && prevStatus !== 'completed') {
1287	                ticket.products.forEach(tp => {
1288	                    const product = db.productos.find(p => p.nombre.toLowerCase().includes(tp.name.toLowerCase()));
1289	                    if (product) {
1290	                        product.stock = Math.max(0, product.stock - tp.qty);
1291	                    }
1292	                });
1293	            }
1294	
1295	            // Si se cancela, recuperar inventario
1296	            if (status === 'cancelled' && (prevStatus === 'confirmed' || prevStatus === 'completed')) {
1297	                ticket.products.forEach(tp => {
1298	                    const product = db.productos.find(p => p.nombre.toLowerCase().includes(tp.name.toLowerCase()));
1299	                    if (product) {
1300	                        product.stock += tp.qty;
1301	                    }
1302	                });
1303	            }
1304	
1305	            saveDatabase();
1306	            renderTickets();
1307	            renderInventory();
1308	            renderStats();
1309	            renderPlanner();
1310	        }
