        function createCamisa3D(container) {
            const scene = new THREE.Scene();
            const camera = new THREE.PerspectiveCamera(75, container.clientWidth / container.clientHeight, 0.1, 1000);
            const renderer = new THREE.WebGLRenderer({ antialias: true, alpha: true });
            renderer.setSize(container.clientWidth, container.clientHeight);
            renderer.setClearColor(0x000000, 0);
            container.appendChild(renderer.domElement);

            const group = new THREE.Group();
            const mat = new THREE.MeshPhongMaterial({ color: 0xffffff, specular: 0x222222, shininess: 30 });
            const body = new THREE.Mesh(new THREE.BoxGeometry(2, 2.5, 0.3), mat);
            group.add(body);

            const lSleeve = new THREE.Mesh(new THREE.BoxGeometry(1, 0.8, 0.25), mat);
            lSleeve.position.set(-1.4, 0.7, 0); lSleeve.rotation.z = -0.3;
            group.add(lSleeve);
            const rSleeve = new THREE.Mesh(new THREE.BoxGeometry(1, 0.8, 0.25), mat);
            rSleeve.position.set(1.4, 0.7, 0); rSleeve.rotation.z = 0.3;
            group.add(rSleeve);

            const print = new THREE.Mesh(new THREE.PlaneGeometry(1.5, 1.8), new THREE.MeshPhongMaterial({ color: 0xe040fb }));
            print.position.set(0, 0, 0.16);
            group.add(print);

            scene.add(group);
            scene.add(new THREE.DirectionalLight(0xffffff, 1));
            scene.add(new THREE.AmbientLight(0xffffff, 0.5));
            camera.position.z = 5;

            let mx = 0, my = 0;
            container.addEventListener('mousemove', (e) => {
                const rect = container.getBoundingClientRect();
                mx = (e.clientX - rect.left) / rect.width * 2 - 1;
                my = (e.clientY - rect.top) / rect.height * 2 - 1;
            });

            function animate() {
                requestAnimationFrame(animate);
                group.rotation.y += (mx * 0.4 - group.rotation.y) * 0.05;
                group.rotation.x += (my * 0.2 - group.rotation.x) * 0.05;
                group.rotation.y += 0.005;
                renderer.render(scene, camera);
            }
            animate();
            camisaModel = { group, mat };
        }

        function hexToRgb(hex) {
            const r = parseInt(hex.slice(1,3),16)/255;
            const g = parseInt(hex.slice(3,5),16)/255;
            const b = parseInt(hex.slice(5,7),16)/255;
            return {r, g, b};
        }

        function setTazaColor(hex) {
            if (!tazaModel) return;
            const rgb = hexToRgb(hex);
            gsap.to(tazaModel.bodyMat.color, { ...rgb, duration: 0.5 });
        }

        function setCamisaColor(hex) {
            if (!camisaModel) return;
            const rgb = hexToRgb(hex);
            gsap.to(camisaModel.mat.color, { ...rgb, duration: 0.5 });
        }

        const observer = new IntersectionObserver((entries) => {
            entries.forEach(entry => {
                if (entry.isIntersecting && !entry.target.dataset.init) {
                    if (entry.target.id === 'taza-viewer') { createTaza3D(entry.target); entry.target.dataset.init = 'true'; }
                    if (entry.target.id === 'camisa-viewer') { createCamisa3D(entry.target); entry.target.dataset.init = 'true'; }
                }
            });
        }, { threshold: 0.3 });

        observer.observe(document.getElementById('taza-viewer'));
        observer.observe(document.getElementById('camisa-viewer'));

        document.querySelectorAll('#taza-colors .color-btn').forEach(btn => {
            btn.addEventListener('click', () => {
                document.querySelectorAll('#taza-colors .color-btn').forEach(b => b.classList.remove('active'));
                btn.classList.add('active');
                setTazaColor(btn.dataset.color);
            });
        });

        document.querySelectorAll('#camisa-colors .color-btn').forEach(btn => {
            btn.addEventListener('click', () => {
                document.querySelectorAll('#camisa-colors .color-btn').forEach(b => b.classList.remove('active'));
                btn.classList.add('active');
                setCamisaColor(btn.dataset.color);
            });
        });
    </script>
</body>
</html>

