// Initialize
        function initApp() {
            renderCategoryTabs();
            renderProducts();
            renderTickets();
            renderWebTickets();
            renderInventory();
            renderStats();
            renderPlanner();
            initCharts();
            renderRecentTickets();
            updateWebTicketsBadge();
        }

        // Web Tickets
        function renderWebTickets(filter = 'all') {
            const container = document.getElementById('webTicketsContainer');
            let tickets = db.tickets.filter(t => t.origen === 'web');
            if (filter !== 'all') {
                tickets = tickets.filter(t => t.status === filter);
            }

            if (tickets.length === 0) {
                container.innerHTML = '<p style="text-align: center; color: var(--text-muted); padding: 2rem;">No hay pedidos web</p>';
                return;
            }

            const statusLabels = { pending: 'Nuevo', confirmed: 'Confirmado', completed: 'Completado', cancelled: 'Cancelado' };

            container.innerHTML = tickets.map(t => {
                const total = t.products.reduce((sum, p) => sum + (p.price * p.qty), 0);
                return `
                    <div class="ticket-card web-ticket-card ${t.status}">
                        ${t.status === 'pending' ? '<span class="web-tag">🆕 NUEVO</span>' : ''}
                        <div class="web-ticket-header">
                            <span class="ticket-id">#${t.id}</span>
                            <span class="ticket-status ${t.status}">${statusLabels[t.status]}</span>
                        </div>
                        <div class="customer-info">
                            <strong>👤 ${t.client}</strong><br>
                            📧 ${t.email || 'N/A'} | 📱 ${t.telefono || 'N/A'}<br>
                            📍 ${t.deliveryAddress || 'Sin dirección'}
                        </div>
                        <div class="ticket-products">
                            ${t.products.map(p => `
                                <div class="ticket-product">
                                    <span>${p.name} x${p.qty}</span>
                                    <span>$${(p.price * p.qty).toFixed(2)}</span>
                                </div>
                            `).join('')}
                        </div>
                        ${t.notes ? `<div class="ticket-date">📝 Nota: ${t.notes}</div>` : ''}
                        <div class="ticket-total">
                            <span>Total</span>
                            <span>$${total.toFixed(2)}</span>
                        </div>
                        <div class="ticket-actions">
                            ${t.status === 'pending' ? `
                                <button class="btn btn-success" onclick="updateWebTicketStatus(${t.id}, 'confirmed')">✅ Confirmar</button>
                            ` : ''}
                            ${t.status === 'confirmed' ? `
                                <button class="btn btn-primary" onclick="updateWebTicketStatus(${t.id}, 'completed')">📦 Completar</button>
                            ` : ''}
                            ${t.status !== 'cancelled' && t.status !== 'completed' ? `
                                <button class="btn btn-danger" onclick="updateWebTicketStatus(${t.id}, 'cancelled')">❌ Cancelar</button>
                            ` : ''}
                        </div>
                    </div>
                `;
            }).join('');
        }

        function updateWebTicketStatus(id, status) {
            const ticket = db.tickets.find(t => t.id === id);
            if (!ticket) return;

            const prevStatus = ticket.status;
            ticket.status = status;

            // Restore stock on cancel
            if (status === 'cancelled' && (prevStatus === 'confirmed' || prevStatus === 'completed')) {
                ticket.products.forEach(tp => {
                    const product = db.productos.find(p => p.nombre.toLowerCase().includes(tp.name.toLowerCase()));
                    if (product) {
                        product.stock += tp.qty;
                    }
                });
            }

            saveDatabase();
            renderWebTickets();
            renderInventory();
            updateWebTicketsBadge();
        }

        function updateWebTicketsBadge() {
            const pending = db.tickets.filter(t => t.origen === 'web' && t.status === 'pending').length;
            const badge = document.getElementById('webTicketsBadge');
            const count = document.getElementById('webOrdersCount');
            if (badge) {
                badge.textContent = pending;
                badge.style.display = pending > 0 ? 'inline' : 'none';
            }
            if (count) {
                count.textContent = pending + ' nuevos';
                count.style.display = pending > 0 ? 'inline' : 'none';
            }
        }

